package security

import (
	"bufio"
	"context"
	crand "crypto/rand"
	"encoding/hex"
	"encoding/json"
	"errors"
	"io"
	"net"
	"net/http"
	"strconv"
	"strings"
	"time"

	"socialpredict/logger"
)

const (
	requestIDHeader = logger.RequestIDHeader
)

type requestIDContextKey struct{}

// RequestBoundaryMiddleware attaches stable request correlation and completion logging at the HTTP boundary.
func RequestBoundaryMiddleware() func(http.Handler) http.Handler {
	return newRequestBoundaryMiddleware(logger.Standard(), time.Now, defaultRequestID)
}

// RequestIDFromContext returns the boundary request identifier when middleware has attached one.
func RequestIDFromContext(ctx context.Context) string {
	if ctx == nil {
		return ""
	}

	requestID, _ := ctx.Value(requestIDContextKey{}).(string)
	return requestID
}

func newRequestBoundaryMiddleware(runtimeLogger *logger.RuntimeLogger, now func() time.Time, newRequestID func() string) func(http.Handler) http.Handler {
	if runtimeLogger == nil {
		runtimeLogger = logger.Standard()
	}
	if now == nil {
		now = time.Now
	}
	if newRequestID == nil {
		newRequestID = defaultRequestID
	}

	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			startedAt := now()
			requestID := incomingRequestID(r, newRequestID)

			w.Header().Set(requestIDHeader, requestID)
			ctx := context.WithValue(r.Context(), requestIDContextKey{}, requestID)
			ctx = logger.ContextWithRequestCorrelation(ctx, requestID, r.Header.Get("Traceparent"))
			r = r.WithContext(ctx)

			recorder := &requestBoundaryWriter{
				ResponseWriter: w,
				statusCode:     http.StatusOK,
			}

			defer func() {
				if recovered := recover(); recovered != nil {
					if !recorder.wroteHeader {
						writeRecoveredPanicResponse(recorder)
					} else {
						recorder.statusCode = http.StatusInternalServerError
					}

					runtimeLogger.Error(
						"middleware",
						"request panic recovered",
						errors.New("panic recovered"),
						requestBoundaryFields(r, requestID, recorder.statusCode, now().Sub(startedAt), "panic")...,
					)
				}
			}()

			next.ServeHTTP(recorder, r)

			fields := requestBoundaryFields(r, requestID, recorder.statusCode, now().Sub(startedAt), "")

			switch {
			case recorder.statusCode >= http.StatusInternalServerError:
				runtimeLogger.Error("middleware", "request failed", nil, fields...)
			case recorder.statusCode >= http.StatusBadRequest:
				runtimeLogger.Warn("middleware", "request completed with client error", fields...)
			default:
				runtimeLogger.Info("middleware", "request completed", fields...)
			}
		})
	}
}

func requestBoundaryFields(r *http.Request, requestID string, statusCode int, duration time.Duration, errorType string) []logger.Field {
	fields := []logger.Field{
		logger.Operation("RequestBoundary"),
		logger.RequestID(requestID),
		logger.Method(requestMethod(r)),
		logger.Path(requestPath(r)),
		logger.StatusCode(statusCode),
		logger.DurationMS(duration),
	}
	if address := strings.TrimSpace(getClientIP(r)); address != "" {
		fields = append(fields, logger.Address(address))
	}
	fields = append(fields, logger.TraceContextFromTraceparent(r.Header.Get("Traceparent"))...)
	if strings.TrimSpace(errorType) != "" {
		fields = append(fields, logger.ErrorType(errorType))
	}

	return fields
}

func writeRecoveredPanicResponse(w http.ResponseWriter) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusInternalServerError)
	_ = json.NewEncoder(w).Encode(struct {
		OK     bool   `json:"ok"`
		Reason string `json:"reason"`
	}{
		OK:     false,
		Reason: "INTERNAL_ERROR",
	})
}

func defaultRequestID() string {
	var raw [16]byte
	if _, err := crand.Read(raw[:]); err == nil {
		return hex.EncodeToString(raw[:])
	}

	return strconv.FormatInt(time.Now().UnixNano(), 16)
}

func incomingRequestID(r *http.Request, newRequestID func() string) string {
	if r != nil {
		if requestID := strings.TrimSpace(r.Header.Get(requestIDHeader)); requestID != "" {
			return requestID
		}
	}

	return newRequestID()
}

func requestMethod(r *http.Request) string {
	if r == nil {
		return ""
	}
	return strings.TrimSpace(r.Method)
}

func requestPath(r *http.Request) string {
	if r == nil || r.URL == nil {
		return ""
	}

	path := strings.TrimSpace(r.URL.EscapedPath())
	if path == "" {
		return "/"
	}
	return path
}

type requestBoundaryWriter struct {
	http.ResponseWriter
	statusCode  int
	wroteHeader bool
}

func (w *requestBoundaryWriter) Header() http.Header {
	return w.ResponseWriter.Header()
}

func (w *requestBoundaryWriter) WriteHeader(statusCode int) {
	w.statusCode = statusCode
	w.wroteHeader = true
	w.ResponseWriter.WriteHeader(statusCode)
}

func (w *requestBoundaryWriter) Write(data []byte) (int, error) {
	if !w.wroteHeader {
		w.wroteHeader = true
	}
	return w.ResponseWriter.Write(data)
}

func (w *requestBoundaryWriter) Flush() {
	flusher, ok := w.ResponseWriter.(http.Flusher)
	if !ok {
		return
	}
	flusher.Flush()
}

func (w *requestBoundaryWriter) Hijack() (net.Conn, *bufio.ReadWriter, error) {
	hijacker, ok := w.ResponseWriter.(http.Hijacker)
	if !ok {
		return nil, nil, http.ErrNotSupported
	}
	return hijacker.Hijack()
}

func (w *requestBoundaryWriter) Push(target string, opts *http.PushOptions) error {
	pusher, ok := w.ResponseWriter.(http.Pusher)
	if !ok {
		return http.ErrNotSupported
	}
	return pusher.Push(target, opts)
}

func (w *requestBoundaryWriter) ReadFrom(reader io.Reader) (int64, error) {
	if readerFrom, ok := w.ResponseWriter.(io.ReaderFrom); ok {
		return readerFrom.ReadFrom(reader)
	}
	return io.Copy(w.ResponseWriter, reader)
}

func (w *requestBoundaryWriter) Unwrap() http.ResponseWriter {
	return w.ResponseWriter
}

package security

import (
	"net/http"
	"sync"
	"time"

	"golang.org/x/time/rate"
)

// RateLimiter manages rate limiting for different clients/IPs
type RateLimiter struct {
	limiters map[string]*rate.Limiter
	mu       sync.RWMutex
	rate     rate.Limit
	burst    int
	cleanup  time.Duration
}

// NewRateLimiter creates a new rate limiter
func NewRateLimiter(r rate.Limit, b int, cleanup time.Duration) *RateLimiter {
	rl := &RateLimiter{
		limiters: make(map[string]*rate.Limiter),
		rate:     r,
		burst:    b,
		cleanup:  cleanup,
	}

	// Start cleanup goroutine
	go rl.cleanupRoutine()

	return rl
}

// GetLimiter returns the rate limiter for a given key (IP address)
func (rl *RateLimiter) GetLimiter(key string) *rate.Limiter {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	limiter, exists := rl.limiters[key]
	if !exists {
		limiter = rate.NewLimiter(rl.rate, rl.burst)
		rl.limiters[key] = limiter
	}

	return limiter
}

// cleanupRoutine periodically removes unused limiters
func (rl *RateLimiter) cleanupRoutine() {
	ticker := time.NewTicker(rl.cleanup)
	defer ticker.Stop()

	for range ticker.C {
		rl.mu.Lock()
		for key, limiter := range rl.limiters {
			// Remove limiters that haven't been used recently
			if limiter.TokensAt(time.Now()) == float64(rl.burst) {
				delete(rl.limiters, key)
			}
		}
		rl.mu.Unlock()
	}
}

// RateLimitConfig holds configuration for different rate limits
type RateLimitConfig struct {
	LoginRate       rate.Limit // requests per second for login attempts
	LoginBurst      int        // max burst for login attempts
	GeneralRate     rate.Limit // requests per second for general API
	GeneralBurst    int        // max burst for general API
	CleanupInterval time.Duration
}

// DefaultRateLimitConfig returns sensible default rate limits
func DefaultRateLimitConfig() RateLimitConfig {
	return RateLimitConfig{
		LoginRate:       rate.Every(10 * time.Second), // 1 login attempt per 10 seconds
		LoginBurst:      3,                            // Allow burst of 3 attempts
		GeneralRate:     rate.Every(time.Second),      // 1 request per second
		GeneralBurst:    10,                           // Allow burst of 10 requests
		CleanupInterval: 5 * time.Minute,              // Cleanup every 5 minutes
	}
}

// RateLimitMiddleware creates a rate limiting middleware
func RateLimitMiddleware(limiter *RateLimiter) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Get client IP
			ip := getClientIP(r)

			// Check rate limit
			if !limiter.GetLimiter(ip).Allow() {
				http.Error(w, "Rate limit exceeded. Please try again later.", http.StatusTooManyRequests)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// LoginRateLimitMiddleware creates a stricter rate limit for login endpoints
func LoginRateLimitMiddleware(limiter *RateLimiter) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Get client IP
			ip := getClientIP(r)

			// Check rate limit
			if !limiter.GetLimiter(ip).Allow() {
				http.Error(w, "Too many login attempts. Please try again later.", http.StatusTooManyRequests)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// getClientIP extracts the client IP address from the request
func getClientIP(r *http.Request) string {
	// Check for forwarded IP first (if behind proxy)
	forwarded := r.Header.Get("X-Forwarded-For")
	if forwarded != "" {
		// X-Forwarded-For can contain multiple IPs, get the first one
		if idx := len(forwarded); idx > 0 {
			if commaIdx := 0; commaIdx < idx {
				for i, c := range forwarded {
					if c == ',' {
						commaIdx = i
						break
					}
				}
				if commaIdx > 0 {
					return forwarded[:commaIdx]
				}
			}
			return forwarded
		}
	}

	// Check for real IP header
	if realIP := r.Header.Get("X-Real-IP"); realIP != "" {
		return realIP
	}

	// Fall back to remote address
	return r.RemoteAddr
}

// RateLimitManager manages multiple rate limiters for different endpoints
type RateLimitManager struct {
	loginLimiter   *RateLimiter
	generalLimiter *RateLimiter
}

// NewRateLimitManager creates a new rate limit manager with default configuration
func NewRateLimitManager() *RateLimitManager {
	config := DefaultRateLimitConfig()

	return &RateLimitManager{
		loginLimiter: NewRateLimiter(
			config.LoginRate,
			config.LoginBurst,
			config.CleanupInterval,
		),
		generalLimiter: NewRateLimiter(
			config.GeneralRate,
			config.GeneralBurst,
			config.CleanupInterval,
		),
	}
}

// NewCustomRateLimitManager creates a rate limit manager with custom configuration
func NewCustomRateLimitManager(config RateLimitConfig) *RateLimitManager {
	return &RateLimitManager{
		loginLimiter: NewRateLimiter(
			config.LoginRate,
			config.LoginBurst,
			config.CleanupInterval,
		),
		generalLimiter: NewRateLimiter(
			config.GeneralRate,
			config.GeneralBurst,
			config.CleanupInterval,
		),
	}
}

// GetLoginMiddleware returns the login rate limiting middleware
func (rlm *RateLimitManager) GetLoginMiddleware() func(http.Handler) http.Handler {
	return LoginRateLimitMiddleware(rlm.loginLimiter)
}

// GetGeneralMiddleware returns the general rate limiting middleware
func (rlm *RateLimitManager) GetGeneralMiddleware() func(http.Handler) http.Handler {
	return RateLimitMiddleware(rlm.generalLimiter)
}

package logger

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"errors"
	"fmt"
	"net/http"
	"strings"
	"time"
)

const (
	RequestIDHeader           = "X-Request-Id"
	clientClosedRequestStatus = 499

	requestIDContextKey contextKey = "request_id"
	traceIDContextKey   contextKey = "trace_id"
	spanIDContextKey    contextKey = "span_id"
)

type contextKey string

// RequestIDFromContext retrieves the current request id from context when present.
func RequestIDFromContext(ctx context.Context) string {
	return contextValue(ctx, requestIDContextKey)
}

// TraceIDFromContext retrieves the current trace id from context when present.
func TraceIDFromContext(ctx context.Context) string {
	return contextValue(ctx, traceIDContextKey)
}

// SpanIDFromContext retrieves the current span id from context when present.
func SpanIDFromContext(ctx context.Context) string {
	return contextValue(ctx, spanIDContextKey)
}

func contextValue(ctx context.Context, key contextKey) string {
	if ctx == nil {
		return ""
	}
	value, _ := ctx.Value(key).(string)
	return value
}

// ContextWithRequestCorrelation attaches the request-boundary correlation fields
// used by runtime logging and legacy handler diagnostics.
func ContextWithRequestCorrelation(ctx context.Context, requestID, traceparent string) context.Context {
	if ctx == nil {
		ctx = context.Background()
	}

	requestID = strings.TrimSpace(requestID)
	if requestID != "" {
		ctx = context.WithValue(ctx, requestIDContextKey, requestID)
	}

	traceID, spanID := parseTraceparent(traceparent)
	if traceID != "" {
		ctx = context.WithValue(ctx, traceIDContextKey, traceID)
	}
	if spanID != "" {
		ctx = context.WithValue(ctx, spanIDContextKey, spanID)
	}

	return ctx
}

// RequestLoggingMiddleware logs one completion line per request and propagates
// stable request/correlation identifiers at the runtime boundary.
func RequestLoggingMiddleware(next http.Handler) http.Handler {
	if next == nil {
		return http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			http.Error(w, "handler unavailable", http.StatusInternalServerError)
		})
	}

	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()

		requestID := strings.TrimSpace(r.Header.Get(RequestIDHeader))
		if requestID == "" {
			requestID = newRequestID()
		}

		traceID, spanID := parseTraceparent(r.Header.Get("traceparent"))
		ctx := ContextWithRequestCorrelation(r.Context(), requestID, r.Header.Get("traceparent"))

		r = r.WithContext(ctx)

		recorder := &statusRecorder{ResponseWriter: w, statusCode: http.StatusOK}
		recorder.Header().Set(RequestIDHeader, requestID)

		next.ServeHTTP(recorder, r)

		statusCode := recorder.statusCode
		canceled := isRequestCanceled(r.Context().Err())
		if canceled && !recorder.wroteHeader {
			statusCode = clientClosedRequestStatus
		}

		duration := time.Since(start).Milliseconds()
		message := fmt.Sprintf(
			"method=%s path=%s status=%d duration_ms=%d request_id=%s trace_id=%s span_id=%s remote_addr=%s",
			r.Method,
			r.URL.Path,
			statusCode,
			duration,
			requestID,
			orDash(traceID),
			orDash(spanID),
			orDash(remoteAddress(r)),
		)

		switch {
		case canceled && !recorder.wroteHeader:
			LogWarn("HTTPRequest", "Canceled", message)
		case statusCode >= http.StatusInternalServerError:
			LogError("HTTPRequest", "Complete", errors.New(message))
		case statusCode >= http.StatusBadRequest:
			LogWarn("HTTPRequest", "Complete", message)
		default:
			LogInfo("HTTPRequest", "Complete", message)
		}
	})
}

type statusRecorder struct {
	http.ResponseWriter
	statusCode  int
	wroteHeader bool
}

func (w *statusRecorder) WriteHeader(statusCode int) {
	w.statusCode = statusCode
	w.wroteHeader = true
	w.ResponseWriter.WriteHeader(statusCode)
}

func (w *statusRecorder) Write(b []byte) (int, error) {
	if !w.wroteHeader {
		w.wroteHeader = true
	}
	return w.ResponseWriter.Write(b)
}

func isRequestCanceled(err error) bool {
	return errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded)
}

func newRequestID() string {
	buf := make([]byte, 16)
	if _, err := rand.Read(buf); err != nil {
		return fmt.Sprintf("fallback-%d", time.Now().UnixNano())
	}
	return hex.EncodeToString(buf)
}

func parseTraceparent(header string) (traceID string, spanID string) {
	parts := strings.Split(strings.TrimSpace(header), "-")
	if len(parts) != 4 {
		return "", ""
	}

	if len(parts[1]) == 32 {
		traceID = parts[1]
	}
	if len(parts[2]) == 16 {
		spanID = parts[2]
	}

	return traceID, spanID
}

func orDash(value string) string {
	if strings.TrimSpace(value) == "" {
		return "-"
	}
	return value
}

func remoteAddress(r *http.Request) string {
	if r == nil {
		return ""
	}
	if forwardedFor := strings.TrimSpace(r.Header.Get("X-Forwarded-For")); forwardedFor != "" {
		return forwardedFor
	}
	if realIP := strings.TrimSpace(r.Header.Get("X-Real-Ip")); realIP != "" {
		return realIP
	}
	return r.RemoteAddr
}

